import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...";
const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
    "ODAK_TALEP",
    "ODAK_TEDARİK",
    "ODAK_VERİLEMEYEN",
];

const ALLOWED_PROJECTS = new Set([
    "BUNGE LÜLEBURGAZ FTL",
    "REKA FTL",
    "EKSUN GIDA FTL",
    "SARUHAN FTL",
    "PEPSİ FTL",
    "MUTLU MAKARNA SPOT FTL",
    "TEKİRDAĞ UN FTL",
    "AYDINLI MODA FTL",
    "ADKOTURK FTL",
    "ADKOTURK FTL ENERJİ İÇECEĞİ",
    "SGS FTL",
    "BSH FTL",
    "ALTERNA GIDA FTL",
    "DERYA OFİS FTL",
    "SAPRO FTL",
    "MARMARA CAM FTL",
    "FAKİR FTL",
    "MODERN KARTON FTL",
    "KÜÇÜKBAY FTL",
]);

function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization:
                            "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                const validItems = items.filter(
                    (item) =>
                        item.OrderStatu !== 200 &&
                        item.TMSVehicleRequestDocumentNo &&
                        item.ProjectName &&
                        ALLOWED_PROJECTS.has(item.ProjectName)
                );

                const projectMap = new Map();

                validItems.forEach((item) => {
                    const project = item.ProjectName;
                    const despatch = !!item.TMSDespatchDocumentNo;
                    const vehicleNo = item.TMSVehicleRequestDocumentNo;
                    const key = `${project}-${vehicleNo}`;

                    if (!projectMap.has(project)) {
                        projectMap.set(project, {
                            ProjectName: project,
                            Talep: 0,
                            Tedarik: 0,
                            Verilemeyen: 0,
                            _seenKeys: new Set(),
                        });
                    }

                    const projData = projectMap.get(project);
                    if (!projData._seenKeys.has(key)) {
                        projData._seenKeys.add(key);
                        projData.Talep += 1;
                        despatch ? projData.Tedarik++ : projData.Verilemeyen++;
                    }
                });

                const finalData = Array.from(projectMap.values()).map((p) => {
                    delete p._seenKeys;
                    return p;
                });

                setOdakData(finalData);
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);

    useEffect(() => {
        if (data.length === 0 || odakData.length === 0) return;

        const header = data[0];
        const rows = data.slice(1);

        const grouped = odakData.map((odakProj) => {
            const odakName = odakProj.ProjectName.trim().toUpperCase();

            const relatedRows = rows.filter((row) => {
                const supaName = row["PROJE ADI"]?.trim().toUpperCase();
                return (
                    supaName.includes(odakName) ||
                    odakName.includes(supaName) ||
                    supaName.startsWith(odakName) ||
                    odakName.startsWith(supaName)
                );
            });

            if (relatedRows.length === 0) return null;

            const mergedRow = {};

            columnOrder.forEach((col) => {
                if (col === "PROJE ADI") {
                    mergedRow[col] = odakProj.ProjectName;
                } else if (col === "TED. %") {
                    const totalTedarik = relatedRows.reduce((acc, r) => acc + (parseFloat(r["TEDARİK"]) || 0), 0);
                    const totalTalep = relatedRows.reduce((acc, r) => acc + (parseFloat(r["TALEP"]) || 0), 0);
                    const ratio = totalTalep > 0 ? totalTedarik / totalTalep : 0;
                    mergedRow[col] = ratio;
                } else if (!isNaN(parseFloat(relatedRows[0]?.[col]))) {
                    mergedRow[col] = relatedRows.reduce((acc, r) => acc + (parseFloat(r[col]) || 0), 0);
                } else {
                    mergedRow[col] = "";
                }
            });

            mergedRow["ODAK_TALEP"] = odakProj.Talep;
            mergedRow["ODAK_TEDARİK"] = odakProj.Tedarik;
            mergedRow["ODAK_VERİLEMEYEN"] = odakProj.Verilemeyen;

            return mergedRow;
        });

        const cleaned = grouped.filter(Boolean);
        setData([header, ...cleaned]);
    }, [odakData]);

    return (
        <div className="app-container">
            <div className="section">
                <h2>🟢 Supabase + Odak Verileri (Gruplanmış)</h2>
                {data.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {columnOrder.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {data.slice(1).map((row, idx) => (
                                    <tr key={idx}>
                                        {columnOrder.map((col, i) => {
                                            const value = row[col];
                                            let displayValue = value;
                                            let style = {};

                                            if (col === "TED. %") {
                                                const parsed = parseFloat(value);
                                                if (!isNaN(parsed)) {
                                                    const percentage = Math.round(parsed * 100);
                                                    displayValue = `%${percentage}`;
                                                    style = {
                                                        color:
                                                            percentage < 70
                                                                ? "#e74c3c"
                                                                : percentage < 90
                                                                    ? "#f39c12"
                                                                    : "#27ae60",
                                                        fontWeight: "bold",
                                                    };
                                                }
                                            } else if (
                                                col === "HEDEF ÜSTÜ SEFER" ||
                                                col === "HEDEF ALTI SEFER" ||
                                                col === "HEDEF SEFER"
                                            ) {
                                                const parsed = parseFloat(value);
                                                if (!isNaN(parsed)) {
                                                    displayValue = `${parsed.toLocaleString("tr-TR")} ₺`;
                                                    if (col === "HEDEF ÜSTÜ SEFER") {
                                                        style = {
                                                            color: parsed > 0 ? "#27ae60" : "#e74c3c",
                                                            fontWeight: "bold",
                                                        };
                                                    }
                                                }
                                            }

                                            return (
                                                <td key={i} style={style}>
                                                    {displayValue}
                                                </td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <p className="loading">Yükleniyor...</p>
                )}
            </div>
        </div>
    );
}

export default App;
